"use strict";parserFactory.register("untamedalley.com",()=>new UntamedAlleyParser);class UntamedAlleyParser extends Parser{constructor(){super()}async getChapterUrls(e,r){return(await this.walkTocPages(e,this.chaptersFromDom,this.nextTocPageUrl,r)).reverse()}chaptersFromDom(e){return[...e.querySelectorAll("#primary h2 a")].map(e=>util.hyperLinkToChapter(e))}nextTocPageUrl(e){return e.querySelector("div.nav-previous a")?.href}findContent(e){return e.querySelector("div.entry-content")}extractTitleImpl(e){return e.querySelector(".page-title")}findChapterTitle(e){return e.querySelector(".entry-title")}}